<?php
namespace Zclone\services;
use Zclone\Core\Database; use Zclone\Core\EventDispatcher;
final class UniverseTickService { public function __construct(private Database $db, private ResourceService $resources, private EventDispatcher $events) {} public function tick(): void { foreach($this->db->all("select p.*, u.speed from planets p join universes u on u.id=p.universe_id where p.last_resource_at < now() - interval '5 seconds' limit 500") as $p){ $rows=$this->db->all('select type,level from planet_buildings where planet_id=?',[$p['id']]); $r=$this->resources->accrue($p,array_column($rows,'level','type')); $this->db->exec('update planets set metal=?,crystal=?,deuterium=?,energy=?,last_resource_at=now() where id=?',[$r['metal'],$r['crystal'],$r['deuterium'],$r['energy'],$p['id']]); $this->events->dispatch('ResourceUpdated',['planet_id'=>$p['id'],'resources'=>$r]); } foreach($this->db->all('select * from build_queue where finish_at <= now() and completed_at is null limit 100') as $q){ $this->db->exec('insert into planet_buildings (planet_id,type,level) values (?,?,?) on conflict (planet_id,type) do update set level=excluded.level',[$q['planet_id'],$q['type'],$q['level']]); $this->db->exec('update build_queue set completed_at=now() where id=?',[$q['id']]); $this->events->dispatch('BuildingFinished',$q); } } }
